const v8 = require('v8');
const fs = require('fs');

if (process.memoryUsage().heapUsed > THRESHOLD) {
  const snap = v8.writeHeapSnapshot();
  console.log(`Heap snapshot written to ${snap}`);
}
```

**Pattern:** take 2 heap snapshots minutes apart → compare in DevTools → objects growing between snapshots = leak source. Filter by "Objects allocated between Snapshot 1 and 2" to find retained objects.

