function get(key) {
  if (!cache.has(key)) cache.set(key, computeExpensive(key));
  return cache.get(key);
}

// After (bounded)
import { LRUCache } from 'lru-cache';
const cache = new LRUCache({ max: 1000 });
```

Take two heap snapshots a few minutes apart, filter by "Objects allocated between snapshots" — that shows you exactly what's accumulating.

